		function LoadSubgrupoLSD(me)
{ 
	var subGrupo;
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	if (Ctrl('nmbCodSugrupoLSD').GetCValue() !="")
	{ 
		subGrupo = nSQL.GetOBJ(Ctrl("main").getResource("qry_subgrupo"), "<PARAM e_lsd=\""+Ctrl('nmbCodSugrupoLSD').GetCValue()+"\" />"); 					
    if(subGrupo.d_subgrupo !=null)
    {
			Ctrl('txbSubgrupo').SetCValue(subGrupo.d_subgrupo);
			return true;
		}
		else
		{ 
			Ctrl('nmbCodSugrupoLSD').SetCValue('');
			Ctrl('txbSubgrupo').SetCValue("");
			alert('Ningún rango LSD coincide con el código ingresado');
			return false;
		}
	}
	else
	{
		Ctrl('txbSubgrupo').SetCValue("");					
	}
}    

function VER_SUBGRUPO()
{	
	openNewFlowWait("NucleusRH.Base.Liquidacion.SubgrupoLSD.SUBGRUPO.MAIN.STD.autoflow","SELECT","<DATOS />",new ObjtectResult(),"L");
}

function ObjtectResult()
{
	this.processResult= function(xmlin)
	{  
		var xmlLSDin = new NomadXML(xmlin);
		var subGrupo;
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();

		if (xmlLSDin.GetAttr("cancel")=='1')
			return false;

		subGrupo = nSQL.GetOBJ(Ctrl("main").getResource("qry_oiSubgrupo"), "<PARAM oi_subgrupo=\""+xmlLSDin.GetAttr("ID")+"\" />");
		Ctrl('txbSubgrupo').SetCValue(subGrupo.d_subgrupo);
		Ctrl('nmbCodSugrupoLSD').SetCValue(subGrupo.e_lsd_inicial);
	}
}
